# Generated by Kiro using Auto, reviewed by ccharland
BeforeAll {
    $script:ScriptPath = "$PSScriptRoot/../../Scripts/Test-HelpCompliance.ps1"
}

Describe 'Test-HelpCompliance' {

    BeforeAll {
        # Create temp directories to simulate module and scripts
        $script:TestRoot = Join-Path ([System.IO.Path]::GetTempPath()) "HelpComplianceTests_$([guid]::NewGuid().ToString('N'))"
        $script:ModuleDir = Join-Path $script:TestRoot 'src' 'TestModule'
        $script:ScriptsDir = Join-Path $script:TestRoot 'Scripts'
        New-Item -ItemType Directory -Path $script:ModuleDir -Force | Out-Null
        New-Item -ItemType Directory -Path $script:ScriptsDir -Force | Out-Null
    }

    AfterAll {
        # Remove the test module if loaded
        if (Get-Module -Name TestModule -ErrorAction SilentlyContinue) {
            Remove-Module TestModule -Force
        }
        if (Test-Path $script:TestRoot) {
            Remove-Item -Recurse -Force $script:TestRoot
        }
    }

    Context 'Path validation' {

        It 'Throws when module manifest path does not exist' {
            { & $script:ScriptPath -ModulePath 'C:\NonExistent\Fake.psd1' -ScriptPath $script:ScriptsDir } |
            Should -Throw '*Module manifest not found*'
        }

        It 'Throws when scripts directory does not exist' {
            # Create a minimal valid manifest for this test
            $manifestPath = Join-Path $script:ModuleDir 'TestModule.psd1'
            $manifestContent = "@{ ModuleVersion = '1.0'; FunctionsToExport = @() }"
            Set-Content -Path $manifestPath -Value $manifestContent

            { & $script:ScriptPath -ModulePath $manifestPath -ScriptPath 'C:\NonExistent\Scripts' } |
            Should -Throw '*Scripts directory not found*'
        }
    }

    Context 'Functions with valid help pass' {

        BeforeAll {
            # Create a module with a function that has proper help
            $script:ModulePsm1 = Join-Path $script:ModuleDir 'TestModule.psm1'
            $script:ManifestPsd1 = Join-Path $script:ModuleDir 'TestModule.psd1'

            $moduleContent = @'
function Get-TestItem {
    <#
    .SYNOPSIS
        Gets a test item for validation purposes.
    #>
    [CmdletBinding()]
    param()
    return 'test'
}
'@
            Set-Content -Path $script:ModulePsm1 -Value $moduleContent

            $manifestContent = @"
@{
    RootModule        = 'TestModule.psm1'
    ModuleVersion     = '1.0.0'
    GUID              = '$([guid]::NewGuid().ToString())'
    FunctionsToExport = @('Get-TestItem')
}
"@
            Set-Content -Path $script:ManifestPsd1 -Value $manifestContent

            # Create a script with valid help
            $scriptContent = @'
<#
.SYNOPSIS
    A test script with proper help.
#>
param()
Write-Output 'done'
'@
            Set-Content -Path (Join-Path $script:ScriptsDir 'Good-Script.ps1') -Value $scriptContent
        }

        It 'Passes when all functions and scripts have valid help' {
            { & $script:ScriptPath -ModulePath $script:ManifestPsd1 -ScriptPath $script:ScriptsDir } |
            Should -Not -Throw
        }
    }

    Context 'Functions missing help fail' {

        BeforeAll {
            # Create a module with a function that has no help
            $script:ModulePsm1NoHelp = Join-Path $script:ModuleDir 'TestModule.psm1'
            $script:ManifestPsd1NoHelp = Join-Path $script:ModuleDir 'TestModule.psd1'

            $moduleContent = @'
function Get-NoHelpItem {
    [CmdletBinding()]
    param()
    return 'no help here'
}
'@
            Set-Content -Path $script:ModulePsm1NoHelp -Value $moduleContent

            $manifestContent = @"
@{
    RootModule        = 'TestModule.psm1'
    ModuleVersion     = '1.0.0'
    GUID              = '$([guid]::NewGuid().ToString())'
    FunctionsToExport = @('Get-NoHelpItem')
}
"@
            Set-Content -Path $script:ManifestPsd1NoHelp -Value $manifestContent
        }

        It 'Throws when a function is missing help' {
            { & $script:ScriptPath -ModulePath $script:ManifestPsd1NoHelp -ScriptPath $script:ScriptsDir } |
            Should -Throw '*missing required comment-based help*'
        }
    }

    Context 'Scripts missing help fail' {

        BeforeAll {
            # Create a module with valid help so function check passes
            $script:ModulePsm1Good = Join-Path $script:ModuleDir 'TestModule.psm1'
            $script:ManifestPsd1Good = Join-Path $script:ModuleDir 'TestModule.psd1'

            $moduleContent = @'
function Get-GoodItem {
    <#
    .SYNOPSIS
        A properly documented function.
    #>
    [CmdletBinding()]
    param()
    return 'good'
}
'@
            Set-Content -Path $script:ModulePsm1Good -Value $moduleContent

            $manifestContent = @"
@{
    RootModule        = 'TestModule.psm1'
    ModuleVersion     = '1.0.0'
    GUID              = '$([guid]::NewGuid().ToString())'
    FunctionsToExport = @('Get-GoodItem')
}
"@
            Set-Content -Path $script:ManifestPsd1Good -Value $manifestContent

            # Create a script with NO help
            $script:BadScriptsDir = Join-Path $script:TestRoot 'BadScripts'
            New-Item -ItemType Directory -Path $script:BadScriptsDir -Force | Out-Null
            Set-Content -Path (Join-Path $script:BadScriptsDir 'No-Help.ps1') -Value 'Write-Output "no help"'
        }

        It 'Throws when a script is missing help' {
            { & $script:ScriptPath -ModulePath $script:ManifestPsd1Good -ScriptPath $script:BadScriptsDir } |
            Should -Throw '*missing required comment-based help*'
        }
    }

    Context 'Module with DefaultCommandPrefix' {

        BeforeAll {
            $script:PrefixModuleDir = Join-Path $script:TestRoot 'PrefixModule'
            New-Item -ItemType Directory -Path $script:PrefixModuleDir -Force | Out-Null

            $moduleContent = @'
function Get-PrefixedItem {
    <#
    .SYNOPSIS
        A function that will be prefixed.
    #>
    [CmdletBinding()]
    param()
    return 'prefixed'
}
'@
            Set-Content -Path (Join-Path $script:PrefixModuleDir 'PrefixModule.psm1') -Value $moduleContent

            $script:PrefixManifest = Join-Path $script:PrefixModuleDir 'PrefixModule.psd1'
            $manifestContent = @"
@{
    RootModule           = 'PrefixModule.psm1'
    ModuleVersion        = '1.0.0'
    GUID                 = '$([guid]::NewGuid().ToString())'
    FunctionsToExport    = @('Get-PrefixedItem')
    DefaultCommandPrefix = 'XX'
}
"@
            Set-Content -Path $script:PrefixManifest -Value $manifestContent

            # Use a scripts dir with a valid script
            $script:PrefixScriptsDir = Join-Path $script:TestRoot 'PrefixScripts'
            New-Item -ItemType Directory -Path $script:PrefixScriptsDir -Force | Out-Null
            $scriptContent = @'
<#
.SYNOPSIS
    Valid script for prefix test.
#>
param()
'@
            Set-Content -Path (Join-Path $script:PrefixScriptsDir 'Valid.ps1') -Value $scriptContent
        }

        It 'Passes when using DefaultCommandPrefix and function has help' {
            { & $script:ScriptPath -ModulePath $script:PrefixManifest -ScriptPath $script:PrefixScriptsDir } |
            Should -Not -Throw
        }
    }

    Context 'Empty FunctionsToExport with valid scripts passes' {

        BeforeAll {
            $script:EmptyFuncDir = Join-Path $script:TestRoot 'EmptyFuncModule'
            New-Item -ItemType Directory -Path $script:EmptyFuncDir -Force | Out-Null

            Set-Content -Path (Join-Path $script:EmptyFuncDir 'Empty.psm1') -Value '# empty module'

            $script:EmptyFuncManifest = Join-Path $script:EmptyFuncDir 'Empty.psd1'
            $manifestContent = @"
@{
    RootModule        = 'Empty.psm1'
    ModuleVersion     = '1.0.0'
    GUID              = '$([guid]::NewGuid().ToString())'
    FunctionsToExport = @()
}
"@
            Set-Content -Path $script:EmptyFuncManifest -Value $manifestContent

            $script:EmptyFuncScriptsDir = Join-Path $script:TestRoot 'EmptyFuncScripts'
            New-Item -ItemType Directory -Path $script:EmptyFuncScriptsDir -Force | Out-Null
            $scriptContent = @'
<#
.SYNOPSIS
    Valid script in empty-func test.
#>
param()
'@
            Set-Content -Path (Join-Path $script:EmptyFuncScriptsDir 'Ok.ps1') -Value $scriptContent
        }

        It 'Passes with no exported functions and valid scripts' {
            { & $script:ScriptPath -ModulePath $script:EmptyFuncManifest -ScriptPath $script:EmptyFuncScriptsDir } |
            Should -Not -Throw
        }
    }
}
